const { execSync } = require('child_process');
const fs = require('fs');
const item = $input.item.json;
const cwd = 'c:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow';
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;

const startTime = new Date();
let stdout = '', stderr = '';
try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe' }).toString();
} catch (e) {
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}
const duration = ((new Date() - startTime) / 1000).toFixed(2);

let allCases = [];
let stats = { total: 0, passed: 0, failed: 0 };
try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.total = stats.passed + stats.failed + (jsonData.stats.skipped || 0);
    }
    function processSuite(suite, parents = []) {
      const suiteTitle = parents.concat(suite.title || []).filter(t => t);
      if (suite.specs) {
        suite.specs.forEach(spec => {
          const specTitle = suiteTitle.concat(spec.title).join(' > ');
          spec.tests.forEach(test => {
            const results = test.results || [];
            const latestResult = results[results.length - 1];
            if (latestResult) {
               const isFailed = latestResult.status === 'failed' || latestResult.status === 'timedOut';
               const screenshot = (latestResult.attachments || []).find(a => a.name === 'screenshot');
               let errorMsg = isFailed ? (latestResult.errors?.map(e => e.message || e.stack).join('\n\n') || latestResult.error?.message || 'Unknown error') : '';
               let finalScreenshotPath = null;
               if (screenshot) {
                   const originalPath = (screenshot.path.includes(':') || screenshot.path.startsWith('/') ? screenshot.path : `${cwd}/${screenshot.path}`).replace(/\\/g, '/');
                   const pathModule = require('path');
                   const safePath = `C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results/ss_${Date.now()}_${pathModule.basename(originalPath)}`;
                   try { fs.copyFileSync(originalPath, safePath); finalScreenshotPath = safePath; } catch(e) { finalScreenshotPath = originalPath; }
               }
               allCases.push({
                   filename: item.filename,
                   testTitle: specTitle,
                   status: isFailed ? 'failed' : 'passed',
                   error: errorMsg.substring(0, 3000),
                   screenshotPath: finalScreenshotPath,
                   duration: (latestResult.duration / 1000).toFixed(2) + 's'
               });
            }
          });
        });
      }
      if (suite.suites) suite.suites.forEach(s => processSuite(s, suiteTitle));
    }
    if (jsonData.suites) jsonData.suites.forEach(s => processSuite(s));
  }
} catch (e) { }

const savePath = `C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results/res_${Date.now()}_${item.filename}.json`;
fs.writeFileSync(savePath, JSON.stringify({ filename: item.filename, duration: duration + 's', stats, cases: allCases }));

return { json: { ...item, status: 'saved' } };

const fs = require('fs');
const path = require('path');
const dir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';
if (!fs.existsSync(dir)) return { json: { count: 0 } };

const files = fs.readdirSync(dir).filter(f => f.endsWith('.json'));
let allCases = [];
let failedCases = [];
let totalPassed = 0, totalFailed = 0, totalCases = 0;
let html = '<table style="width:100%; border-collapse: collapse; font-family: Arial; border: 1px solid #ddd;">\n';
html += '<tr style="background-color:#007bff; color:white;"><th style="padding:12px;text-align:left;">Test Script</th><th style="padding:12px;">Total</th><th style="padding:12px;">Passed</th><th style="padding:12px;">Failed</th><th style="padding:12px;">Duration</th></tr>\n';

for (const file of files) {
  const data = JSON.parse(fs.readFileSync(path.join(dir, file)));
  const p = data.stats?.passed || 0;
  const f = data.stats?.failed || 0;
  const t = p + f;
  totalPassed += p;
  totalFailed += f;
  totalCases += t;
  const bg = f > 0 ? '#ffebee' : '#f1f8e9';
  html += `<tr style="background-color:${bg}; border-bottom: 1px solid #ddd;">`;
  html += `<td style="padding:10px;"><b>${data.filename}</b></td>`;
  html += `<td style="padding:10px;text-align:center;">${t}</td>`;
  html += `<td style="padding:10px;text-align:center;color:green;">${p}</td>`;
  html += `<td style="padding:10px;text-align:center;color:red;">${f}</td>`;
  html += `<td style="padding:10px;text-align:center;">${data.duration}</td>`;
  html += `</tr>\n`;

  if (data.cases) {
     data.cases.forEach(c => {
       allCases.push(c);
       if (c.status === 'failed') failedCases.push(c);
     });
  }
}
html += '</table>';

return {
  json: {
    totalFiles: files.length,
    totalCases,
    passed: totalPassed,
    failed: totalFailed,
    html,
    allCasesList: allCases,
    failedCasesList: failedCases
  }
};

